exports.createBatch = function(user, batch, callback){
    exports.getUserPanoDataByUserId(user.id, function(err, userdata){
        if(err || !userdata){
            //userdata does not exits. create one
            var batch_data = [batch];
            db.userpanos.save({user:user, batch_data:batch_data}, function(err, data){
                callback(err, data);
            });
        }else{
            if(userdata && userdata.batch_data){
                userdata.batch_data.push(batch);
                db.userpanos.update({'user.id': user.id}, {$set:{ batch_data: userdata.batch_data}}, function(err, data){
                    callback(err, data);
                })
            }
        }
    })
}

