exports.createBatch = function(req, res){
    walkintologger.info("Inside create batch");
    var user = req.user;
    var id = uuidV4().replace(/-/g, '');
    var name = "";
    var status = batchTemplate.userPanoStatus.NEW;
    var created_date = new Date();
    var panos = [];
    var aBatch = batchTemplate.batch(id, name, status, created_date, panos);
    aBatch.optimized = true
    panouploaddb.createBatch(user, aBatch, function(err, data){
        if(err){
            walkintologger.error("Error while creating new batch");
            res.status(500).send('{status: "failed", errMessage: "Error while saving new batch data"}');
        }else{
            //send back new batch data
            panouploaddb.getBatchDataByUseridAndBatchid(user.id, id, function(err, data){
                res.send(data);
            })

        }
    })
}

