    NEW : 'new',
    UPLOAD_SUCCESS: 'upload_success',
    UPLOAD_FAILED: 'upload_failed',
    TILING_FAILED: 'tiling_failed',
    TILING_SUCCESFUL: 'tiling_successful',
    IMPORT_SUCCESSFUL: 'import_successful',
    IMPORT_FAILED: 'import_failed',
    PROCESSING_STARTED:'processing_started',
    MIGRATED_FROM_PANOHOST: 'migrated_from_panohost'
};

var socketNotificationTypeMap = {
    batch_status_update: 'batch_status_update',
    pano_status_update: 'pano_status_update',
    thumbnail_update: 'thumbnail_update'
}

var batch = function(id, name, status, created_date, panos){
    this.id = id;
    this.name = name;
    this.status = status;
    this.created_date = created_date,
    this.panos = panos;    
};

var pano_data = function(id, status, cloud_key, file_metadata, thumbnail_url,pano_import_url){
    this.id = id;
    this.status = status;
    this.cloud_key = cloud_key;
    this.file_metadata = file_metadata;
    this.thumbnail_url = thumbnail_url;
    if(pano_import_url){
        this.pano_import_url = pano_import_url;
    }
};

